import React, { memo } from 'react';
import type { MenuProps } from 'antd';
import { Button, Dropdown, Space } from 'antd';
import { useTranslation } from 'react-i18next';
import { BsFillMoonStarsFill, BsFillSunFill } from 'react-icons/bs';
import { useChangeLanguage } from '../../Hooks/useChangeLanguage';
import translationEN from '../../translate/en.json';
import translationAR from '../../translate/ar.json';

i18n.use(initReactI18next).init({
  resources: {
    en: {
      translation: translationEN
    },
    ar: {
      translation: translationAR
    }
  },
  lng: 'en', 
  interpolation: {
    escapeValue: false
  }
});
const Theme: React.FC = () => {
  const { currentlanguage, changelanguage } = useChangeLanguage();
  const { t } = useTranslation();

  const EnLanguage = memo(() => (
    <div onClick={EnLanguageClickHandler}>
      <BsFillSunFill />
      {t('En')}
    </div>
  ));

  const ArLanguage = memo(() => (
    <div onClick={ArLanguageClickHandler}>
      <BsFillMoonStarsFill />
      {t('Ar')}
    </div>
  ));


  const EnLanguageClickHandler = React.useCallback(() => {
    changelanguage('En');
  }, [changelanguage]);

  const ArLanguageClickHandler = React.useCallback(() => {
    changelanguage('Ar');
  }, [changelanguage]);

  const items: MenuProps['items'] = [
    {
      key: '1',
      label: <EnLanguage />,
    },
    {
      key: '2',
      label: <ArLanguage />,
    },
  ];

  return (
    <Space direction="vertical">
      <Dropdown menu={{ items }} placement="top">
        <Button>{currentlanguage === 'En' ? <ArLanguage /> : <EnLanguage />}</Button>
      </Dropdown>
    </Space>
  );
};

export default Theme;
